sql:
SELECT name, description
FROM engine_features
WHERE feature_id = 0;

SELECT COUNT(*) 
FROM texture_formats 
WHERE compression = 1;

SELECT name, data_type
FROM internal_formats
WHERE red_bits = 8;

SELECT COUNT(format_id) AS formats_with_mipmap_support
FROM internal_formats
WHERE mipmap_support = 1;

SELECT COUNT(*) AS low_performance_count
FROM format_documentation
WHERE performance_impact = 'Low performance impact';

SELECT COUNT(*) 
   FROM engine_features 
   WHERE is_deprecated = 0;

SELECT DISTINCT name
FROM internal_formats
WHERE anisotropic_filtering = 1;

external_knowledge:
- "non-revoked permission" refers to a permission record where `is_revoked` equals 0; 
- "non-deprecated" refers to a feature where `is_deprecated` equals 0; 
- "at least one active permission" refers to the existence of a permission for a user where `is_revoked` equals 0.
